content.content:
  1→#!/usr/bin/env node
  2→/**
  3→ * DKCE Template Generator
  4→ * 
  5→ * Reads a canonical model YAML and produces fill templates for every rule
  6→ * with condition: null or action: null. Each template contains:
  7→ *   - The rule's context (entity, intent, glossary terms, scenarios)
  8→ *   - [REQUIRED] slots that AI fill must populate
  9→ *   - Structural constraints derived from the canonical model
 10→ *   - A machine-readable JSON output format for the AI fill stage
 11→ * 
 12→ * Usage:
 13→ *   node template-generator.js <canonical-model.yaml> [--output-dir <dir>]
 14→ *   node template-generator.js example.canonical-model.yaml --output-dir ./templates
 15→ */
 16→
 17→'use strict';
 18→
 19→const fs   = require('fs');
 20→const path = require('path');
 21→const yaml = require('js-yaml');
 22→
 23→// ── CLI ───────────────────────────────────────────────────────────────────────
 24→
 25→const args = process.argv.slice(2);
 26→if (args.length === 0 || args[0] === '--help') {
 27→  console.log('Usage: node template-generator.js <canonical-model.yaml> [--output-dir <dir>]');
 28→  process.exit(0);
 29→}
 30→
 31→const modelPath = args[0];
 32→const outputDirIndex = args.indexOf('--output-dir');
 33→const outputDir = outputDirIndex !== -1 ? args[outputDirIndex + 1] : './templates';
 34→
 35→if (!fs.existsSync(modelPath)) {
 36→  console.error(`Error: model file not found: ${modelPath}`);
 37→  process.exit(1);
 38→}
 39→
 40→// ── Load model ────────────────────────────────────────────────────────────────
 41→
 42→const model = yaml.load(fs.readFileSync(modelPath, 'utf8'));
 43→
 44→// ── Index helpers — build lookup maps for O(1) access ────────────────────────
 45→
 46→function buildIndex(arr, key = 'id') {
 47→  return Object.fromEntries((arr || []).map(item => [item[key], item]));
 48→}
 49→
 50→const glossaryIndex   = buildIndex(model.glossary);
 51→const intentIndex     = buildIndex(model.intents);
 52→const entityIndex     = buildIndex(model.entities);
 53→const scenarioIndex   = buildIndex(model.scenarios);
 54→const eventIndex      = buildIndex(model.events || []);
 55→const operationIndex  = buildIndex(model.operations || []);
 56→
 57→function fieldIndex(entity) {
 58→  return buildIndex(entity.fields || []);
 59→}
 60→
 61→// ── Find rules needing fill ───────────────────────────────────────────────────
 62→
 63→const rulesNeedingFill = (model.rules || []).filter(
 64→  r => r.condition === null || r.action === null
 65→);
 66→
 67→if (rulesNeedingFill.length === 0) {
 68→  console.log('No rules with null condition or action found. Nothing to generate.');
 69→  process.exit(0);
 70→}
 71→
 72→console.log(`Found ${rulesNeedingFill.length} rule(s) needing AI fill.`);
 73→
 74→// ── Ensure output dir ─────────────────────────────────────────────────────────
 75→
 76→fs.mkdirSync(outputDir, { recursive: true });
 77→
 78→// ── Core builder functions ────────────────────────────────────────────────────
 79→
 80→/**
 81→ * Resolves all glossary terms relevant to a rule:
 82→ * - From the rule's entity fields
 83→ * - From the rule's intent
 84→ * - From the entity's glossaryRef itself
 85→ */
 86→function resolveGlossaryContext(rule, entity) {
 87→  const refs = new Set();
 88→
 89→  // entity-level glossaryRef
 90→  if (entity.glossaryRef) refs.add(entity.glossaryRef);
 91→
 92→  // all field glossaryRefs
 93→  for (const field of entity.fields || []) {
 94→    if (field.glossaryRef) refs.add(field.glossaryRef);
 95→  }
 96→
 97→  // intent glossaryRefs
 98→  const intent = intentIndex[rule.intentRef];
 99→  if (intent) {
100→    for (const ref of intent.glossaryRefs || []) refs.add(ref);
101→  }
102→
103→  return [...refs]
104→    .filter(id => glossaryIndex[id])
105→    .map(id => {
106→      const term = glossaryIndex[id];
107→      const out = {
108→        id: term.id,
109→        term: term.term,
110→        definition: term.definition.trim()
111→      };
112→      if (term.precision) out.precision = term.precision;
113→      if (term.counterexamples?.length) out.counterexamples = term.counterexamples;
114→      return out;
115→    });
116→}
117→
118→/**
119→ * Builds the field manifest for a rule's entity.
120→ * This is what the AI uses to know what fields it can reference in conditions/actions.
121→ */
122→function buildFieldManifest(entity) {
123→  return (entity.fields || []).map(field => {
124→    const entry = {
125→      id:       field.id,
126→      name:     field.name,
127→      type:     field.type,
128→      required: field.required || false,
129→      nullable: field.nullable || false,
130→    };
131→    if (field.enumValues)   entry.enumValues   = field.enumValues;
132→    if (field.validation)   entry.validation   = field.validation;
133→    if (field.immutable)    entry.immutable     = true;
134→    if (field.systemField)  entry.systemField   = true;
135→    if (field.glossaryRef)  entry.glossaryRef   = field.glossaryRef;
136→    if (field.refEntity)    entry.refEntity     = field.refEntity;
137→    if (field.defaultValue !== undefined) entry.defaultValue = field.defaultValue;
138→    return entry;
139→  });
140→}
141→
142→/**
143→ * Resolves scenarios for a rule and formats them as concrete examples.
144→ * These are the holdout set — they define what "correct" looks like.
145→ */
146→function resolveScenarios(rule) {
147→  return (rule.scenarioRefs || [])
148→    .filter(id => scenarioIndex[id])
149→    .map(id => {
150→      const s = scenarioIndex[id];
151→      const out = {
152→        id:           s.id,
153→        coverageType: s.coverageType,
154→        given:        s.given,
155→        when:         s.when,
156→        then:         s.then,
157→        priority:     s.priority || 'must-pass',
158→      };
159→      if (s.fieldRefs?.length) {
160→        out.fieldValues = s.fieldRefs.map(fr => ({
161→          field: fr.fieldId,
162→          value: fr.value
163→        }));
164→      }
165→      return out;
166→    });
167→}
168→
169→/**
170→ * Describes the valid operators for a given field type.
171→ * Helps AI fill choose appropriate operators.
172→ */
173→function validOperatorsForType(fieldType) {
174→  const map = {
175→    string:   ['eq', 'neq', 'contains', 'starts-with', 'ends-with', 'is-null', 'is-not-null'],
176→    integer:  ['eq', 'neq', 'gt', 'gte', 'lt', 'lte', 'in', 'not-in', 'is-null', 'is-not-null'],
177→    decimal:  ['eq', 'neq', 'gt', 'gte', 'lt', 'lte', 'is-null', 'is-not-null'],
178→    boolean:  ['eq', 'neq'],
179→    datetime: ['eq', 'neq', 'gt', 'gte', 'lt', 'lte', 'is-null', 'is-not-null'],
180→    date:     ['eq', 'neq', 'gt', 'gte', 'lt', 'lte', 'is-null', 'is-not-null'],
181→    uuid:     ['eq', 'neq', 'is-null', 'is-not-null'],
182→    enum:     ['eq', 'neq', 'in', 'not-in'],
183→    array:    ['contains', 'is-null', 'is-not-null'],
184→    object:   ['is-null', 'is-not-null'],
185→  };
186→  return map[fieldType] || ['eq', 'neq'];
187→}
188→
189→/**
190→ * Describes the valid action types for a given field type.
191→ */
192→function validActionsForType(fieldType) {
193→  const map = {
194→    string:   ['set'],
195→    integer:  ['set'],
196→    decimal:  ['set'],
197→    boolean:  ['set'],
198→    datetime: ['set'],
199→    date:     ['set'],
200→    uuid:     ['set'],
201→    enum:     ['set'],
202→    array:    ['set', 'append', 'remove'],
203→    object:   ['set'],
204→  };
205→  return map[fieldType] || ['set'];
206→}
207→
208→/**
209→ * Describes the value constraints for an action on a given field.
210→ * Returns what the AI fill must produce in the 'value' slot.
211→ */
212→function actionValueConstraints(field) {
213→  const base = {
214→    canBeLiteral:    true,
215→    canBeFieldRef:   true,
216→    canBeExpression: ['decimal', 'integer'].includes(field.type),
217→  };
218→
219→  if (field.type === 'enum') {
220→    base.allowedLiterals = field.enumValues;
221→    base.canBeFieldRef = false;
222→    base.canBeExpression = false;
223→  }
224→  if (field.immutable) {
225→    base.note = 'IMMUTABLE: this field cannot be set after creation. Do not generate an action targeting it.';
226→  }
227→  if (field.systemField) {
228→    base.note = 'SYSTEM FIELD: managed automatically. Do not generate an action targeting it.';
229→  }
230→  if (field.validation) {
231→    base.validationConstraints = field.validation;
232→  }
233→
234→  return base;
235→}
236→
237→/**
238→ * Generates the condition slot specification.
239→ * Tells AI fill exactly what structure to produce.
240→ */
241→function conditionSlotSpec(entity, rule) {
242→  const fields = buildFieldManifest(entity);
243→  const mutableFields = fields.filter(f => !f.systemField && !f.immutable);
244→
245→  return {
246→    _slot: 'REQUIRED',
247→    _description: [
248→      'Fill this slot with a RuleCondition that correctly expresses the rule trigger.',
249→      'The condition operates on fields of entity: ' + entity.id,
250→      'Reference only field ids listed in entityFields below.',
251→      'You may compose conditions using: { and: [...] }, { or: [...] }, { not: {...} }',
252→      'Leaf condition form: { field: "<fieldId>", operator: "<op>", value: <value> }',
253→      'For is-null / is-not-null operators, omit value entirely.',
254→    ],
255→    _entityFields: mutableFields.map(f => ({
256→      id:             f.id,
257→      type:           f.type,
258→      enumValues:     f.enumValues,
259→      validOperators: validOperatorsForType(f.type),
