291→    .filter(e => e.entityRef === entity.id)
292→    .map(e => ({ id: e.id, description: e.description || e.name }));
293→
294→  return {
295→    _slot: 'REQUIRED',
296→    _description: [
297→      'Fill this slot with a RuleAction that correctly implements the rule effect.',
298→      'The action operates on fields of entity: ' + entity.id,
299→      'Reference only field ids listed in writableFields below.',
300→      'type: set — assign a value. value can be a literal, { $field } reference, or { $field, $op, $value } expression.',
301→      'type: append / remove — for array fields.',
302→      'type: emit-event — emit a domain event. Use "event" property with an id from registeredEvents.',
303→      'type: call-operation — invoke another operation. Use "operation" property.',
304→      'Chain multiple actions using the "then" array.',
305→    ],
