183→}
184→
185→// ── Call Claude API ───────────────────────────────────────────────────────────
186→
187→async function callClaudeAPI(prompt) {
188→  console.log('Calling Claude API...');
189→
190→  const response = await fetch('https://api.anthropic.com/v1/messages', {
191→    method: 'POST',
192→    headers: { "Content-Type": "application/json", ...(process.env.ANTHROPIC_API_KEY ? { "x-api-key": process.env.ANTHROPIC_API_KEY } : {}) },
193→    body: JSON.stringify({
194→      model:      'claude-sonnet-4-20250514',
195→      max_tokens: 1000,
196→      messages:   [{ role: 'user', content: prompt }]
197→    })
198→  });
199→
200→  if (!response.ok) {
201→    const err = await response.text();
202→    throw new Error(`Claude API error ${response.status}: ${err}`);
203→  }
204→
205→  const data = await response.json();
206→  const text = data.content
207→    .filter(b => b.type === 'text')
208→    .map(b => b.text)
209→    .join('');
210→
211→  return text;
212→}
213→
214→// ── Parse and validate AI response ───────────────────────────────────────────
215→
216→function parseFilledSlots(rawText, slotsNeeded) {
217→  // Strip any markdown code fences the model might add despite instructions
218→  const clean = rawText
219→    .replace(/^```(?:json)?\n?/m, '')
220→    .replace(/\n?```$/m, '')
221→    .trim();
222→
223→  let parsed;
224→  try {
225→    parsed = JSON.parse(clean);
226→  } catch (e) {
227→    throw new Error(`AI response was not valid JSON.\nRaw response:\n${rawText}\nParse error: ${e.message}`);
228→  }
229→
230→  // Verify all required slots are present
231→  for (const slot of slotsNeeded) {
232→    if (!(slot in parsed)) {
233→      throw new Error(`AI response missing required slot: "${slot}". Got keys: ${Object.keys(parsed).join(', ')}`);
234→    }
235→    if (parsed[slot] === null || (typeof parsed[slot] === 'object' && parsed[slot]._slot)) {
236→      throw new Error(`Slot "${slot}" was not filled — still contains template placeholder.`);
237→    }
238→  }
239→
240→  return parsed;
241→}
242→
243→// ── Merge filled slots back into template ─────────────────────────────────────
244→
245→function mergeFilledSlots(template, filledSlots) {
246→  const filled = JSON.parse(JSON.stringify(template)); // deep clone
247→
248→  if (filledSlots.condition !== undefined) {
249→    filled.fill.condition = filledSlots.condition;
250→  }
251→  if (filledSlots.action !== undefined) {
252→    filled.fill.action = filledSlots.action;
253→  }
254→
255→  // Mark as filled in metadata
256→  filled._meta.filledAt = new Date().toISOString();
257→  filled._meta.filledBy = 'claude-sonnet-4-20250514';
258→  filled._meta.status   = 'filled-pending-gate';
259→
260→  return filled;
261→}
262→
263→// ── Structural pre-validation before writing ──────────────────────────────────
264→// Light checks here — deep validation is the Enforcement Gate's job.
265→// We just ensure the filled values are structurally plausible.
266→
267→function preValidate(filledSlots, template) {
268→  const ctx          = template.context;
269→  const entityFields = new Set(ctx.entity.fields.map(f => f.id));
270→  const errors       = [];
271→
272→  function checkCondition(cond, path) {
273→    if (!cond || typeof cond !== 'object') {
274→      errors.push(`${path}: must be an object`); return;
275→    }
276→    if ('and' in cond) {
277→      if (!Array.isArray(cond.and) || cond.and.length < 2)
278→        errors.push(`${path}.and: must be an array with at least 2 elements`);
279→      else cond.and.forEach((c, i) => checkCondition(c, `${path}.and[${i}]`));
280→    } else if ('or' in cond) {
281→      if (!Array.isArray(cond.or) || cond.or.length < 2)
282→        errors.push(`${path}.or: must be array with at least 2 elements`);
283→      else cond.or.forEach((c, i) => checkCondition(c, `${path}.or[${i}]`));
284→    } else if ('not' in cond) {
285→      checkCondition(cond.not, `${path}.not`);
286→    } else {
287→      // leaf
288→      if (!cond.field) errors.push(`${path}: leaf condition missing 'field'`);
289→      else if (!entityFields.has(cond.field))
290→        errors.push(`${path}: field '${cond.field}' not found on entity '${ctx.entity.id}'`);
291→      if (!cond.operator) errors.push(`${path}: leaf condition missing 'operator'`);
292→    }
293→  }
294→
295→  function checkAction(action, path) {
296→    if (!action || typeof action !== 'object') {
297→      errors.push(`${path}: must be an object`); return;
298→    }
299→    const validTypes = ['set', 'append', 'remove', 'emit-event', 'call-operation'];
300→    if (!validTypes.includes(action.type))
301→      errors.push(`${path}.type: '${action.type}' not a valid action type`);
302→
303→    if (['set', 'append', 'remove'].includes(action.type)) {
304→      if (!action.field) errors.push(`${path}: missing 'field' for type '${action.type}'`);
305→      else if (!entityFields.has(action.field))
306→        errors.push(`${path}: field '${action.field}' not found on entity '${ctx.entity.id}'`);
307→      if (action.value === undefined) errors.push(`${path}: missing 'value'`);
308→    }
309→    if (action.type === 'emit-event' && !action.event)
310→      errors.push(`${path}: missing 'event'`);
311→    if (action.type === 'call-operation' && !action.operation)
312→      errors.push(`${path}: missing 'operation'`);
313→    if (action.then) {
314→      if (!Array.isArray(action.then))
315→        errors.push(`${path}.then: must be an array`);
316→      else action.then.forEach((a, i) => checkAction(a, `${path}.then[${i}]`));
317→    }
318→  }
319→
320→  if (filledSlots.condition) checkCondition(filledSlots.condition, 'condition');
321→  if (filledSlots.action)    checkAction(filledSlots.action,    'action');
322→
323→  return errors;
324→}
325→
326→// ── Main ──────────────────────────────────────────────────────────────────────
327→
328→async function main() {
329→  const prompt = buildPrompt(template);
330→
331→  // Show a condensed version of the prompt for visibility
332→  console.log('\nPrompt summary:');
333→  console.log(`  Rule:   ${template.context.rule.id}`);
334→  console.log(`  Entity: ${template.context.entity.id}`);
335→  console.log(`  Slots:  ${slotsNeeded.join(', ')}`);
336→  console.log(`  Scenarios: ${template.context.scenarios.items.length} (holdout set)`);
337→  console.log('');
338→
339→  let rawResponse;
340→  try {
341→    rawResponse = await callClaudeAPI(prompt);
342→  } catch (err) {
343→    console.error(`API call failed: ${err.message}`);
344→    process.exit(1);
345→  }
346→
347→  console.log('Raw AI response:');
348→  console.log(rawResponse);
349→  console.log('');
350→
351→  let filledSlots;
352→  try {
353→    filledSlots = parseFilledSlots(rawResponse, slotsNeeded);
354→  } catch (err) {
355→    console.error(`Parse failed: ${err.message}`);
356→    process.exit(1);
357→  }
358→
359→  const preErrors = preValidate(filledSlots, template);
360→  if (preErrors.length > 0) {
361→    console.error('Pre-validation errors (structural check before gate):');
362→    preErrors.forEach(e => console.error(`  ✗ ${e}`));
363→    console.error('\nFilled slots rejected. Fix the above issues before proceeding to the gate.');
364→    process.exit(1);
365→  }
366→
367→  const filledTemplate = mergeFilledSlots(template, filledSlots);
368→
369→  fs.writeFileSync(outputPath, yaml.dump(filledTemplate, {
370→    indent:      2,
371→    lineWidth:   120,
372→    noRefs:      true,
373→    quotingType: '"',
374→  }));
375→
376→  console.log('Pre-validation: PASSED');
377→  console.log(`Filled template written to: ${outputPath}`);
378→  console.log('');
379→  console.log('Filled slots:');
380→  console.log(JSON.stringify(filledSlots, null, 2));
381→  console.log('');
382→  console.log('Next step: run Enforcement Gate Stage 1');
383→  console.log(`  node gate.js ${outputPath}`);
384→}
385→
386→main().catch(err => {
387→  console.error('Fatal error:', err.message);
388→  process.exit(1);
389→});
